import{_ as e,r as i,o as c,c as u,a as d,w as t,b as n,d as l}from"./app-45f24e0d.js";const p={},h=l("h1",{id:"求婚计划-实施-婚礼仪式💒",tabindex:"-1"},[l("a",{class:"header-anchor",href:"#求婚计划-实施-婚礼仪式💒","aria-hidden":"true"},"#"),n(" 求婚计划+实施+婚礼仪式💒")],-1),a=l("p",null,"宝，万万没想到我会在3年后才在日记里续上第二PART。估计你看到我写的关于我们开始和现在的这些文字，应该会有3分开心，3分好奇，以及4分不满。",-1),r=l("p",null,"不满是什么呢？我猜你应该会想起当时我信誓旦旦地和你承诺，会给你写够100首情诗，如今这个承诺就像无良开发商那样，往后了无音讯。",-1),v=l("p",null,"这种对过往的不满是不是和今天你今天的不满有点相似呢？就是那种你对我满怀期待，但是我完全无所谓的样子——像极之前以及现在我对各种或大或小的承诺无所谓，对求婚无所谓，对仪式感无所谓的欠揍模样。",-1),T=l("p",null,"其实我感觉很有所谓的！——只是在你表示非常不满以后。",-1),f=l("p",null,"我刚刚说，我很不喜欢那种刻意的求婚方式。“那你喜欢哪种方式你倒是给我说呀！”你更生气了，估计又是想到我习惯老是给自己找有的没的借口来掩饰自己因为毫无准备的紧张。",-1),m=l("p",null,"正如你如此了解我一样，我现在也如此的（一半）能洞察你的想法，我这种算不算有进步了呀？",-1),b=l("p",null,"我刚刚认真地想了想，我排斥求婚，可能是我不太喜欢那种“经典求婚”的画面感，“经典求婚”的流程，以及可能以后你对着“经典求婚”的记忆——和未来我们家娃说起他爸之前简陋的、随意的、极其不走心的求婚过程，以及对那时的遗憾。我想做得与众不同一点。",-1),A=l("p",null,"是的，对“求婚”的偏见让我感觉很尬，但是回过头又想想，之所以感觉尴尬，不就是自己都不当一回事吗？如果真的是为之倾注一点心思去准备，那“经典求婚”的流程下，也可以彰显准备者的用心。我之前一直在逃避这个事情，但是类似鸵鸟遇到危险把脑袋插到沙子里的做法必定会导致更大的遗憾，这个事情我怎么就没早点想到呢？",-1),x=l("p",null,"那我和你剧透一下我理想的画面（现编的）：",-1),N=l("p",null,"我会提前请假半天，准备好鲜花、灯饰、气球等环境布置，买一个很贵但很好看的蛋糕，给你录一个小视频，最后凭借我玩密室逃脱的经验，给你设计一个小小的解谜环节。",-1),B=l("ol",null,[l("li",null,[l("p",null,"留一张小纸条，放在显眼的地方（或者后面会打电话提示你）"),l("p",null,"纸条或电话上面会写着："),l("p",null,"神秘小纸条位置的提示（分步骤，不会一下子说出来）：")])],-1),V=l("ul",null,[l("li",null,"“我们家里总共有4个这样的容器”"),l("li",null,"它们颜色一样，但不是放在同一个地方"),l("li",null,"你这两天有解除过"),l("li",null,"和吃的有关"),l("li",null,"周黑鸭")],-1),k=l("ol",null,[l("li",null,"我会把神秘小纸条放在：黄色周黑鸭盒子的里面（厨房-右边）"),l("li",null,"如果你顺利找到我给你的小纸条，就可以沿着线索找到其他几张不同位置的纸条")],-1),w=l("p",null,"不过也很有可能上面的解谜环节无法正常实施，毕竟我这么粗心大意的人，瞒不过我家心思缜密的大宝。",-1),C=l("p",null,"如果是这样的话，那我们就一起看小纸条的内容吧！",-1),P=l("p",null,"第一张小纸条：",-1),E=l("p",null,"味道的回忆最为独特，厨房里有我做过的鱼烫过的虾，你汆过的肉汤酱过的鸡鸭。客厅里有你试过的各种花式馒头和开过的饮料小店。你我共同经历的那些酸甜苦辣咸，柴米酱醋盐，是平凡的味道，但也是永远的味道。爱你，以及爱你我交融的味道。",-1),O=l("p",null,"下一个Tips：平时你帮我剪头发后，我会在做些啥？",-1),R=l("p",null,"第二张小纸条：",-1),S=l("p",null,"我们相识相知，到后面相爱，到现在有时相斥却大多相容。时间过得很快，日历也翻得很快，日历上记录着每次你给我的剪头发的日子，一开始的小心翼翼，到后来的从容自信。我俩之间不也是如此转变吗？爱你，TONY宝，你永远是我爱情的理发师！",-1),Y=l("p",null,"下一个Tips：也许屋子外面会有些线索？",-1),g=l("p",null,"第三张小纸条：",-1),j=l("p",null,"我们一起买的鞋不多，但鞋子伴随我们倒是去过不少地方。我记得我们爬过或低或高的山，走过柔软的沙滩和海风吹拂的长廊，涉过神奇的火山和天坑，窜过的大街小巷和，品过的早茶晚点……这些地方很美，更重要的是，在这些不同美的瞬间，都有你在身边，有了你，才让这些静态的美好成为我脑海里最鲜活的回忆。爱你，你我为彼此之良辰美景！",-1),q=l("p",null,"下一个Tips：在我搬家到布心工业区后，你给我留的小纸条留在了哪里？",-1),y=l("p",null,"第四张小纸条：",-1),z=l("p",null,"我有时候很笨，有时候也很懒。懒得晾衣服，懒得换床单。",-1),D=l("p",null,"我很喜欢我俩一起懒懒地躺在沙发，我的大腿当作你的枕头，快乐地刷抖音",-1),F=l("p",null,"我也很喜欢你给我缝补衣服的样子，现在物质早已不再缺乏，缝补的手艺心思更加难能可贵。爱你，爱你能包容经常犯懒的我。简单的生活也到处充满小确幸！",-1),G=l("p",null,"下一个Tips：我们家里哪里可以找到笔筒？",-1),H=l("p",null,"第五张小纸条：",-1),I=l("p",null,"还记得你之前在康华给我写的信吗？",-1),J=l("p",null,"信很绵长，很细腻，略能体会到主人公当时的一些羞涩，一些倾诉和爱慕。",-1),K=l("p",null,"也许你会把它当成不堪往事的“黑历史”，但我还是珍藏着呢！",-1),L=l("p",null,"纸张很轻，但内容会很重，想起它，让我不禁也联想其他相爱的小故事",-1),M=l("p",null,"如开始异地的奔波，如最初同居的争执，如喜得新屋的喜悦，如初见双方父母的紧张，如偶尔对某些话题的深刻讨论。",-1),Q=l("p",null,"也许搜集一下，就可以整理出“大宝和臭宝的经典语录”？",-1),U=l("p",null,"下一个Tips：看你手机！",-1),W=l("p",null,"（哈哈哈，没猜到我藏在你手机壳里面吧！）",-1),X=l("p",null,"第六张小纸条：",-1),Z=l("p",null,"爱情是什么？是突然有了软肋，又好像是突然有了铠甲。",-1),$=l("p",null,"爱情是你突然觉得，可以不用征服全世界，不用出人头地，不用功成名就，不用腰缠万贯，也能感觉到幸福。",-1),ll=l("p",null,"甚至是你什么都介意，又什么都可以妥协。",-1),tl=l("p",null,"爱情是在正确的时间里，遇到了一个想承诺一生的人。",-1),sl=l("p",null,"亲爱的宝，我想对你说：“我爱你，请嫁给我！”",-1),_l=l("p",null,"今天是求婚的正式实施日子，我上京东买了灯饰气球等道具大礼包，然后订了99朵玫瑰和1个初心蛋糕。",-1),nl=l("p",null,"求婚的惊喜程度特别好，因为我忍住没有透露已经提前回家布置，然后宝就竟然和她同事看了租房，吃了晚饭，还稍微逛了一下人民公园才回来！所以下午4点回家的我，到8点多才给到了她surprise。",-1),ol=l("p",null,"看得出来，她很开心，很感动，笑的可甜了！夸我的走心程度从50分瞬间变到90分。在看我给她录的抖音小视频时，她还感动得眼睛都湿润了。",-1),el=l("p",null,"今天晚上过得非常完美，然后我们12点就各自蹲在电脑和手机前面抢结婚预约号了。12点2分的时候预约系统非常卡，一直进不了系统，让人感叹2020.8.8果然是好日子啊！有惊无险的是后面还是抢到了盐田民政局预约。能看得出来，我宝还是因为没有果断下手去罗湖民政局感觉有点遗憾，不过在12点12分看到所有民政局可预约数量全部都是0的时候，也不那么纠结了，必经能抢到就是最大的幸运！",-1),il=l("p",null,"那后面就是期待拍结婚照、婚纱照、还有明年年底才能入住的新房了！",-1),cl=l("p",null,"感觉整个婚礼准备的流程都很紧张，然后婚礼忙完了以后直接大松了一口气，今天突然想起来准备的过程还没写，现在来简单补充一下。",-1),ul=l("p",null,"领证：当2020.7.7求婚+成功预约领证了以后，第一件事情就是领证啦。结婚证的照片用的是7.25在喜影集拍家庭写真时顺便拍的照片，宝好像不是很满意，但是因为时间来不及了，所以还是只能用那一张。领证地点是盐田民政局，当时我爸妈和我家丈母娘都过来了，双方一起见证的！（说起来也很巧，我今天穿的也是灰色的T，和结婚穿的一样，哈哈！）",-1),dl=l("p",null,"婚庆日期定档：记得是我妈帮我算了好几个日子，但是后面稍微和假期挨边的只能选12.30了，所以最后确定了这个日子。我爸还特地找人设计了婚庆邀请函，哈哈！",-1),pl=l("p",null,"婚纱照：因为婚礼日期选定了12.30，但是那时候还没有拍好婚纱照，所以我们有2个星期的周末一直在找靠谱的工作时。后面在11.2找到了福田的《吉芙视觉婚纱照摄影工作室》，11.22完成了一天的拍摄，大晚上才开车回家。后面感觉果然很靠谱，成片很满意，更神奇的是吉芙把我俩的婚纱照当作他们的美团封面背景了！（就是总价7649有点贵）",-1),hl=l("p",null,"婚庆公司：婚庆公司找的是佳花姐合作过的公司（艾米），费用好像是3万块钱，设计出来的效果也感觉还不错吧。",-1),al=l("p",null,"酒店：安排入住的是豪生酒店，晚宴安排在了新埠岛诺富特。酒席味道一般般，可能对于新郎新娘而言重点永远不在酒席。PS：本来晚宴的酒店想定在鲁能希尔顿的，这样显得气派有点，但是因为那边同时有一个会议包场了导致不了了之。",-1),rl=l("p",null,"婚礼当天：12.30那天感觉一天都是云里雾里的，早上早早起来去酒店迎亲，迎亲完后去老家参加了我爸特地在村里开的喜宴，下午又回到酒店进行拍摄，晚上酒席开场后终于迎来了最隆重的晚宴环节。这个过程中，最累的就是新娘了，宝不仅要配合摄影师拍照，还得抓紧时间换衣服，晚上也没能好好吃一口饭。",-1),vl=l("p",null,"总体而言，这次婚礼虽然很累但是还是很开心，但是也有一些事情我们男方真的没有做到位，让丈母娘他们感觉到了不尊重，这个还真的需要好好反思一下。比如：婚礼现场的红包都是我爸收的，没提前说好引起了分歧、晚宴期间我们男方没有主动和女方亲戚敬酒，连聊天也不主动，让丈母娘他们感觉不太受到尊重等等。",-1);function Tl(fl,ml){const o=i("Tabs");return c(),u("div",null,[h,d(o,{id:"3",data:[{id:"求婚计划（2020年7月4日）"},{id:"求婚实施（2020年7月7日）"},{id:"结婚那些事（2021年8月30日补）"}],active:0},{title0:t(({value:s,isActive:_})=>[n("求婚计划（2020年7月4日）")]),title1:t(({value:s,isActive:_})=>[n("求婚实施（2020年7月7日）")]),title2:t(({value:s,isActive:_})=>[n("结婚那些事（2021年8月30日补）")]),tab0:t(({value:s,isActive:_})=>[a,r,v,T,f,m,b,A,x,N,B,V,k,w,C,P,E,O,R,S,Y,g,j,q,y,z,D,F,G,H,I,J,K,L,M,Q,U,W,X,Z,$,ll,tl,sl]),tab1:t(({value:s,isActive:_})=>[_l,nl,ol,el,il]),tab2:t(({value:s,isActive:_})=>[cl,ul,dl,pl,hl,al,rl,vl]),_:1})])}const Al=e(p,[["render",Tl],["__file","日记里的我-求婚_实施_婚礼仪式.html.vue"]]);export{Al as default};
